def read_many(paths):
    for path in paths:
        yield from read_lines(path)   # flatten sub-generators

all_lines = read_many(["a.log", "b.log"])
# still lazy, still one line at a time

def read_lines(path):
    with open(path) as f:
        for line in f:
            yield line.rstrip("\n")

def only_errors(lines):
    yield from (l for l in lines if "ERROR" in l)

def parse(lines):
    for l in lines:
        ts, _, msg = l.partition(" ERROR ")
        yield {"time": ts, "message": msg}

if __name__ == "__main__":
    pipe = parse(only_errors(read_lines("app.log")))
    for rec in pipe:
        print(rec["time"], rec["message"])
